export interface MathProblem {
  id: string;
  question: string;
  context?: string;
  image?: string;
}

export interface Solution {
  problemId: string;
  steps: string[];
  finalAnswer: string;
  explanation: string;
}

export interface MarkResult {
  score: number;
  totalMarks: number;
  feedback: string;
  corrections: string[];
}

export interface TopicProgress {
  name: string;
  level: number;
  maxLevel: number;
}

export interface CourseData {
  title: string;
  status: 'Novice' | 'Intermediate' | 'Advanced' | 'Master';
  topics: TopicProgress[];
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const solveMathProblem = async (question: string, imageBase64?: string) => {
  const ai = getAI();
  const parts: any[] = [{ text: `Solve this mathematics problem step-by-step: ${question}` }];

  if (imageBase64) {
    parts.push({
      inlineData: {
        mimeType: 'image/png',
        data: imageBase64.split(',')[1] || imageBase64
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      temperature: 0.1,
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          steps: { type: Type.ARRAY, items: { type: Type.STRING } },
          finalAnswer: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['steps', 'finalAnswer', 'explanation']
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const markProblem = async (question: string, studentAnswer: string, rubric: string) => {
  const ai = getAI();
  const prompt = `
    Question: ${question}
    Student Answer: ${studentAnswer}
    Marking Rubric: ${rubric}

    Evaluate the answer based on the rubric. Provide a score out of the total marks and detailed feedback.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      temperature: 0,
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          totalMarks: { type: Type.NUMBER },
          feedback: { type: Type.STRING },
          corrections: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['score', 'totalMarks', 'feedback', 'corrections']
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

