import React, { useState, useRef } from 'react';
import { solveMathProblem } from '../services/geminiService';

const WorksheetSolver: React.FC = () => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSolve = async () => {
    if (!input.trim()) return;
    setLoading(true);
    try {
      const solution = await solveMathProblem(input);
      setResult(solution);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <header className="mb-12">
        <h1 className="text-4xl font-light tracking-tight text-white mb-2">Worksheet Solver</h1>
        <p className="text-zinc-500">Upload a problem or type it out for a step-by-step resolution.</p>
      </header>

      <div className="space-y-6">
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="e.g. Find the volume of the solid of revolution formed when y = x^2 is rotated about the x-axis..."
            className="w-full bg-transparent p-6 text-white placeholder-zinc-600 focus:outline-none min-h-[150px] resize-none math-font"
          />
          <div className="bg-zinc-800/50 p-4 flex justify-between items-center border-t border-zinc-800">
            <div className="flex gap-4">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="text-zinc-400 hover:text-white transition-colors flex items-center gap-2 text-sm"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
                Attach image
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" />
              </button>
            </div>
            <button
              onClick={handleSolve}
              disabled={loading || !input}
              className="px-6 py-2 bg-white text-black font-medium rounded-full hover:bg-zinc-200 transition-all disabled:opacity-50 flex items-center gap-2"
            >
              {loading ? (
                 <span className="animate-pulse">Thinking...</span>
              ) : (
                <>
                  Solve
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
                  </svg>
                </>
              )}
            </button>
          </div>
        </div>

        {result && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-8 mt-12">
            <div className="bg-zinc-900/30 border border-zinc-800 rounded-2xl p-8">
              <h2 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-6">Resolution Steps</h2>
              <div className="space-y-6">
                {result.steps.map((step: string, idx: number) => (
                  <div key={idx} className="flex gap-6 group">
                    <span className="w-6 h-6 rounded-full border border-zinc-800 flex items-center justify-center text-[10px] text-zinc-600 font-mono flex-shrink-0 group-hover:border-zinc-500 transition-colors">
                      {idx + 1}
                    </span>
                    <p className="text-zinc-300 leading-relaxed math-font">{step}</p>
                  </div>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
                 <h2 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-4">Final Answer</h2>
                 <p className="text-2xl font-light text-white math-font">{result.finalAnswer}</p>
              </div>
              <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
                 <h2 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-4">Core Principle</h2>
                 <p className="text-zinc-400 text-sm leading-relaxed">{result.explanation}</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default WorksheetSolver;

import React, { useState } from 'react';
import { markProblem } from '../services/geminiService';

const MOCK_RUBRIC = "1 mark for correct setup of the integral. 1 mark for correct antiderivative. 1 mark for correct evaluation of limits. 1 mark for final units and calculation.";
const EXAMPLE_QUESTION = "Evaluate the integral of 3x^2 from x=0 to x=2.";

const MarkingSystem: React.FC = () => {
  const [studentInput, setStudentInput] = useState('Integral of 3x^2 dx = 3 * (x^3 / 3) = x^3. evaluated at 2 gives 2^3 = 8.');
  const [marking, setMarking] = useState<any>(null);
  const [isMarking, setIsMarking] = useState(false);

  const handleMark = async () => {
    setIsMarking(true);
    try {
      const result = await markProblem(EXAMPLE_QUESTION, studentInput, MOCK_RUBRIC);
      setMarking(result);
    } catch (e) {
      console.error(e);
    } finally {
      setIsMarking(false);
    }
  };

  return (
    <div className="p-8 max-w-5xl mx-auto">
      <header className="mb-12">
        <h1 className="text-4xl font-light tracking-tight text-white mb-2">Auto-Marking Demo</h1>
        <p className="text-zinc-500">Evaluate student work against custom marking rubrics instantly.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <div className="space-y-8">
          <section>
             <h3 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-4">Question Context</h3>
             <div className="p-4 bg-zinc-900 border border-zinc-800 rounded-xl text-zinc-300 math-font text-sm">
                {EXAMPLE_QUESTION}
             </div>
          </section>

          <section>
            <h3 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-4">Marking Rubric</h3>
            <div className="p-4 bg-zinc-900 border border-zinc-800 rounded-xl text-zinc-400 text-xs leading-loose">
               {MOCK_RUBRIC}
            </div>
          </section>

          <section>
             <h3 className="text-xs font-bold uppercase tracking-widest text-zinc-500 mb-4">Student Response</h3>
             <textarea
                value={studentInput}
                onChange={(e) => setStudentInput(e.target.value)}
                className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 text-white focus:outline-none min-h-[150px] math-font text-sm"
             />
          </section>

          <button
            onClick={handleMark}
            disabled={isMarking}
            className="w-full py-3 bg-white text-black font-bold uppercase tracking-widest text-xs rounded-full hover:bg-zinc-200 transition-all disabled:opacity-50"
          >
            {isMarking ? 'Processing Submission...' : 'Execute Evaluation'}
          </button>
        </div>

        <div className="min-h-[400px]">
          {marking ? (
            <div className="bg-white text-black rounded-2xl p-8 space-y-8 animate-in fade-in zoom-in-95 duration-500 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
              <div className="flex justify-between items-center border-b border-zinc-200 pb-6">
                <h2 className="text-2xl font-medium tracking-tight">Evaluation Result</h2>
                <div className="text-center">
                   <div className="text-4xl font-light leading-none">{marking.score}</div>
                   <div className="text-[10px] font-bold text-zinc-400 uppercase tracking-tighter">of {marking.totalMarks} Marks</div>
                </div>
              </div>

              <section>
                 <h4 className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 mb-3">AI Commentary</h4>
                 <p className="text-zinc-600 leading-relaxed text-sm italic">"{marking.feedback}"</p>
              </section>

              <section>
                 <h4 className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 mb-3">Refinement Notes</h4>
                 <ul className="space-y-3">
                    {marking.corrections.map((c: string, i: number) => (
                      <li key={i} className="flex gap-3 text-sm text-zinc-800">
                        <span className="text-zinc-300">—</span> {c}
                      </li>
                    ))}
                 </ul>
              </section>

              <div className="pt-6 border-t border-zinc-100 flex justify-end">
                <div className="flex items-center gap-2 text-[10px] font-bold tracking-widest text-zinc-400">
                   <div className="w-1.5 h-1.5 rounded-full bg-black animate-pulse" />
                   VERIFIED BY LEIBNIZ AI
                </div>
              </div>
            </div>
          ) : (
            <div className="h-full border border-dashed border-zinc-800 rounded-2xl flex flex-col items-center justify-center p-12 text-center opacity-30">
               <svg className="w-12 h-12 text-zinc-600 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
               </svg>
               <p className="text-zinc-600">Pending Evaluation Data...</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default MarkingSystem;

