import React, { useState, useRef, useEffect } from 'react';
import { solveMathProblem } from '../services/geminiService';

const WorksheetSolver: React.FC = () => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 3;
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }, []);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    draw(e);
  };

  const endDrawing = () => {
    setIsDrawing(false);
    const canvas = canvasRef.current;
    if (canvas) {
        const ctx = canvas.getContext('2d');
        ctx?.beginPath();
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    let x, y;
    if ('touches' in e) {
        x = e.touches[0].clientX - rect.left;
        y = e.touches[0].clientY - rect.top;
    } else {
        x = e.clientX - rect.left;
        y = e.clientY - rect.top;
    }

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const clearCanvas = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  };

  const handleSolve = async (useCanvas = false) => {
    setLoading(true);
    try {
      let imageData = undefined;
      if (useCanvas && canvasRef.current) {
        imageData = canvasRef.current.toDataURL('image/png');
      }
      const solution = await solveMathProblem(input || "Solve the handwritten math problem in the image.", imageData);
      setResult(solution);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4 max-w-4xl mx-auto">
      <header className="mb-8 border-b-2 border-black pb-4">
        <h1 className="text-3xl font-bold mb-1">Worksheet Solver</h1>
        <p className="text-xs font-bold text-gray-500">Draw with a stylus or type text problems</p>
      </header>

      <div className="space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex flex-col gap-2">
                <label className="text-[11px] font-bold title-font">Handwriting Input</label>
                <div className="canvas-container bg-white">
                    <canvas
                        ref={canvasRef}
                        width={400}
                        height={300}
                        onMouseDown={startDrawing}
                        onMouseMove={draw}
                        onMouseUp={endDrawing}
                        onMouseOut={endDrawing}
                        onTouchStart={startDrawing}
                        onTouchMove={draw}
                        onTouchEnd={endDrawing}
                        className="w-full touch-none"
                    />
                </div>
                <div className="flex gap-2">
                    <button onClick={clearCanvas} className="flex-1 py-1 text-[10px] font-bold bg-white title-font">CLEAR</button>
                    <button onClick={() => handleSolve(true)} className="flex-1 py-1 text-xl font-bold bg-black text-white title-font">GO</button>
                </div>
            </div>

            <div className="flex flex-col gap-2">
                <label className="text-[11px] font-bold title-font">Text Input</label>
                <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="Type your problem here..."
                    className="w-full bg-white p-4 text-sm font-bold placeholder-gray-300 focus:outline-none h-[300px] resize-none border-2 border-black"
                />
                <button
                    onClick={() => handleSolve(false)}
                    disabled={loading || !input}
                    className="w-full py-2 bg-black text-white font-bold text-xl title-font disabled:opacity-50"
                >
                    {loading ? '...' : 'GO'}
                </button>
            </div>
        </div>

        {result && (
          <div className="mt-8 space-y-4">
            <div className="card bg-white p-4">
              <h2 className="text-[11px] font-bold mb-4 border-b border-black pb-1 title-font">Solution Steps</h2>
              <div className="space-y-2">
                {result.steps.map((step: string, idx: number) => (
                  <div key={idx} className="flex gap-4 items-start text-xs border-b border-gray-100 pb-2">
                    <span className="font-bold">[{idx + 1}]</span>
                    <p className="leading-tight">{step}</p>
                  </div>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="card p-4">
                 <h2 className="text-[11px] font-bold mb-2 title-font">Final Answer</h2>
                 <p className="text-xl font-bold">{result.finalAnswer}</p>
              </div>
              <div className="card p-4">
                 <h2 className="text-[11px] font-bold mb-2 title-font">Explanation</h2>
                 <p className="text-xs text-gray-600 font-bold">{result.explanation}</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default WorksheetSolver;

