                  <div className="text-3xl font-bold italic tracking-wider opacity-80" style={{ fontFamily: '"Courier Prime", monospace', transform: 'rotate(1deg)' }}>
                    = [ x³ ]₀²
                  </div>
                  <div className="text-3xl font-bold italic tracking-wider opacity-80" style={{ fontFamily: '"Courier Prime", monospace', transform: 'rotate(-0.5deg)' }}>
                    = 2³ - 0³
                  </div>
                  <div className="text-3xl font-bold italic tracking-wider opacity-80" style={{ fontFamily: '"Courier Prime", monospace', transform: 'rotate(2deg)' }}>
                    = 6
                  </div>
                  <div className="text-3xl font-bold italic tracking-wider opacity-80 underline underline-offset-8" style={{ fontFamily: '"Courier Prime", monospace', transform: 'rotate(-1deg)' }}>
                    Ans: 6
                  </div>
                </div>

                {/* Feedback Boxes Overlay */}
                {marked && feedbackBoxes.map((box) => (
                  <div
                    key={box.id}
                    className={`absolute border-2 transition-all cursor-help animate-in fade-in zoom-in-90 ${
                      box.type === 'correct' ? 'border-green-600 bg-green-500/10' : 'border-red-600 bg-red-500/10'
                    }`}
                    style={{
                      top: box.top,
                      left: box.left,
                      width: box.width,
                      height: box.height
                    }}
                    onMouseEnter={() => setShowTooltip(box.id)}
                    onMouseLeave={() => setShowTooltip(null)}
                  >
                    {showTooltip === box.id && (
                      <div className="absolute -top-12 left-0 z-20 bg-black text-white p-2 text-[10px] font-bold title-font min-w-[200px] shadow-lg">
                        <div className={`uppercase mb-1 ${box.type === 'correct' ? 'text-green-400' : 'text-red-400'}`}>
                          {box.type === 'correct' ? '✓ Valid' : '✗ Review'}
                        </div>
                        {box.message}
                      </div>
                    )}
                  </div>
                ))}
              </section>
            </div>
          </div>
        </div>

        {/* Controls and Stats */}
        <div className="space-y-4">
          <div className="card p-4 bg-white">
            <h3 className="text-xs font-bold mb-4 border-b border-black pb-1 title-font">Evaluation Control</h3>
            <p className="text-[10px] mb-6 text-gray-500 leading-relaxed font-bold uppercase">
              Click mark to analyze the spatial geometry of the handwritten response against the internal math core.
            </p>

            <button
              onClick={marked ? reset : handleMark}
              disabled={isMarking}
              className="w-full py-4 bg-black text-white font-bold text-2xl title-font hover:bg-gray-900 transition-colors"
            >
              {isMarking ? '...' : marked ? 'RESET' : 'MARK'}
            </button>
          </div>

          {marked && (
            <div className="card p-4 bg-black text-white space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="flex justify-between items-end border-b border-white pb-4">
                <span className="text-[10px] font-bold uppercase title-font">Score</span>
                <span className="text-5xl font-bold title-font">1/4</span>
              </div>

              <div className="space-y-4">
                <section>
                  <h4 className="text-[10px] font-bold text-gray-400 uppercase title-font mb-2">Primary Fault</h4>
                  <p className="text-xs font-bold">Arithmetic error in power evaluation (2^3).</p>
                </section>

                <section>
                  <h4 className="text-[10px] font-bold text-gray-400 uppercase title-font mb-2">AI Summary</h4>
                  <p className="text-[10px] leading-relaxed text-gray-300">
                    Integration process was sound until the numerical evaluation phase. 
                    Candidate demonstrated understanding of the power rule but failed at 
                    basic exponentiation. Recommend focus on arithmetic verification.
                  </p>
                </section>
              </div>
            </div>
          )}

          {!marked && !isMarking && (
            <div className="border-2 border-dashed border-black p-8 flex flex-col items-center justify-center text-center h-48 opacity-20">
               <span className="text-[10px] font-bold title-font">READY_FOR_ANALYSIS</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

