import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const transcribeAndMark = async (problemDescription: string, imageBase64: string) => {
  const ai = getAI();
  const parts: any[] = [
    { text: `Transcribe this student's handwritten working out for the problem: ${problemDescription}. 
             Then, mark it out of 5 based on mathematical correctness.
             Return the transcribed text, the score, and specific feedback.` },
    {
      inlineData: {
        mimeType: 'image/png',
        data: imageBase64.split(',')[1] || imageBase64
      }
    }
  ];

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      temperature: 0.1,
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          transcription: { type: Type.STRING },
          score: { type: Type.NUMBER },
          totalMarks: { type: Type.NUMBER },
          feedback: { type: Type.STRING },
          steps: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['transcription', 'score', 'totalMarks', 'feedback']
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const solveMathProblem = async (question: string, imageBase64?: string) => {
  const ai = getAI();
  const parts: any[] = [{ text: `Solve this mathematics problem step-by-step: ${question}` }];

  if (imageBase64) {
    parts.push({
      inlineData: {
        mimeType: 'image/png',
        data: imageBase64.split(',')[1] || imageBase64
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      temperature: 0.1,
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          steps: { type: Type.ARRAY, items: { type: Type.STRING } },
          finalAnswer: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ['steps', 'finalAnswer', 'explanation']
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const markProblem = async (question: string, studentAnswer: string, rubric: string) => {
  const ai = getAI();
  const prompt = `
    Question: ${question}
    Student Answer: ${studentAnswer}
    Marking Rubric: ${rubric}

    Evaluate the answer based on the rubric. Provide a score out of the total marks and detailed feedback.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      temperature: 0,
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          totalMarks: { type: Type.NUMBER },
          feedback: { type: Type.STRING },
          corrections: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['score', 'totalMarks', 'feedback', 'corrections']
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

import React, { useState, useRef, useEffect } from 'react';
import { transcribeAndMark } from '../services/geminiService';

const PROBLEMS = [
  { id: 1, text: "Evaluate the integral of 3x^2 from x=0 to x=2." },
  { id: 2, text: "Solve for x: log2(x + 4) = 3" }
];

const Problems: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentProblemIdx, setCurrentProblemIdx] = useState(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 3;
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }, []);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    draw(e);
  };

  const endDrawing = () => {
    setIsDrawing(false);
    const canvas = canvasRef.current;
    if (canvas) {
        const ctx = canvas.getContext('2d');
        ctx?.beginPath();
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    let x, y;
    if ('touches' in e) {
        x = e.touches[0].clientX - rect.left;
        y = e.touches[0].clientY - rect.top;
    } else {
        x = e.clientX - rect.left;
        y = e.clientY - rect.top;
    }

    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const clearCanvas = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    setResult(null);
  };

  const handleMark = async () => {
    if (!canvasRef.current) return;
    setLoading(true);
    try {
      const imageData = canvasRef.current.toDataURL('image/png');
      const problem = PROBLEMS[currentProblemIdx].text;
      const response = await transcribeAndMark(problem, imageData);
      setResult(response);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4 max-w-4xl mx-auto">
      <header className="mb-8 border-b-2 border-black pb-4">
        <h1 className="text-3xl font-bold mb-1">Problems</h1>
        <p className="text-xs font-bold text-gray-500">Handwrite your solution for immediate AI grading</p>
      </header>

      <div className="space-y-6">
        <div className="card p-4 bg-gray-50 border-dashed">
            <h3 className="text-[11px] font-bold title-font uppercase mb-2">Active Problem</h3>
            <p className="text-xl font-bold">{PROBLEMS[currentProblemIdx].text}</p>
        </div>

        <div className="flex flex-col gap-2">
            <label className="text-[11px] font-bold title-font uppercase">Your Working Out</label>
            <div className="canvas-container bg-white">
                <canvas
                    ref={canvasRef}
                    width={800}
                    height={400}
                    onMouseDown={startDrawing}
                    onMouseMove={draw}
                    onMouseUp={endDrawing}
                    onMouseOut={endDrawing}
                    onTouchStart={startDrawing}
                    onTouchMove={draw}
                    onTouchEnd={endDrawing}
                    className="w-full touch-none"
                />
            </div>
            <div className="flex gap-2">
                <button onClick={clearCanvas} className="px-4 py-2 text-[10px] font-bold bg-white title-font">CLEAR CANVAS</button>
                <button 
                  onClick={handleMark} 
                  disabled={loading}
                  className="flex-1 py-4 text-2xl font-bold bg-black text-white title-font"
                >
                    {loading ? 'ANALYZING...' : 'MARK'}
                </button>
            </div>
        </div>

        {result && (
          <div className="mt-8 space-y-4 animate-in fade-in slide-in-from-bottom-2">
            <div className="card bg-black text-white p-6 shadow-[4px_4px_0_#ccc]">
              <div className="flex justify-between items-center border-b border-gray-700 pb-4 mb-4">
                 <h2 className="text-xl font-bold title-font">Evaluation Results</h2>
                 <div className="text-4xl font-bold">{result.score}/{result.totalMarks}</div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <section>
                   <h3 className="text-[10px] font-bold text-gray-400 uppercase mb-2">Transcribed Text</h3>
                   <p className="font-mono text-sm bg-gray-900 p-3 border border-gray-800">{result.transcription}</p>
                </section>
                <section>
                   <h3 className="text-[10px] font-bold text-gray-400 uppercase mb-2">AI Feedback</h3>
                   <p className="text-sm leading-relaxed">{result.feedback}</p>
                   {result.steps && result.steps.length > 0 && (
                     <div className="mt-4 space-y-1">
                        <h4 className="text-[9px] font-bold uppercase text-gray-500">Breakdown</h4>
                        {result.steps.map((s: string, i: number) => (
                           <p key={i} className="text-[10px] text-gray-400 italic">— {s}</p>
                        ))}
                     </div>
                   )}
                </section>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Problems;

